const input = $input.first();
let text = '';
let fileName = 'meeting';

// Get text from body - supports raw text, JSON { transcript, title }, or form data
if (input.json.body && typeof input.json.body === 'object') {
  text = input.json.body.transcript || input.json.body.text || '';
  fileName = input.json.body.title || input.json.body.fileName || 'meeting';
} else if (typeof input.json.body === 'string') {
  text = input.json.body;
} else if (input.json.transcript) {
  text = input.json.transcript;
  fileName = input.json.title || 'meeting';
} else {
  // Try raw body
  text = input.json.rawBody || input.json.data || '';
}

if (!text || text.trim().length < 20) {
  throw new Error('No transcript provided. POST JSON with { "transcript": "...", "title": "..." }');
}

// Detect format from content
let ext = 'txt';
if (text.startsWith('WEBVTT')) ext = 'vtt';
else if (/^\d+\r?\n\d{2}:\d{2}:\d{2},\d{3}/.test(text)) ext = 'srt';
else if (/^\d+:\d{2}:\d{2}\.\d{3},/.test(text)) ext = 'sbv';

// Strip timestamps from subtitle formats
if (ext === 'vtt') {
  text = text.replace(/^WEBVTT[\s\S]*?\n\n/, '');
  text = text.replace(/^\d+\s*\n/gm, '');
  text = text.replace(/\d{2}:\d{2}[:\.]\d{2,3}\s*-->\s*\d{2}:\d{2}[:\.]\d{2,3}[^\n]*\n/g, '');
  text = text.replace(/\n{3,}/g, '\n\n');
} else if (ext === 'srt') {
  text = text.replace(/^\d+\s*\n/gm, '');
  text = text.replace(/\d{2}:\d{2}:\d{2},\d{3}\s*-->\s*\d{2}:\d{2}:\d{2},\d{3}[^\n]*\n/g, '');
  text = text.replace(/\n{3,}/g, '\n\n');
} else if (ext === 'sbv') {
  text = text.replace(/^\d+:\d{2}:\d{2}\.\d{3},\d+:\d{2}:\d{2}\.\d{3}\s*\n/gm, '');
  text = text.replace(/\n{3,}/g, '\n\n');
}

text = text.trim();

let meetingTitle = fileName.replace(/\.[^.]+$/, '').replace(/^\d{4}-\d{2}-\d{2}[-_]?/, '').replace(/[-_]/g, ' ').trim();
if (!meetingTitle) meetingTitle = 'Meeting';

const dateLabel = new Date().toISOString().split('T')[0];

const prompt = `You are an expert meeting analyst. Analyze this transcript and create structured meeting notes.

MEETING: ${meetingTitle}
DATE: ${dateLabel}

TRANSCRIPT:
${text.substring(0, 100000)}

Create structured notes in this exact format:

# Meeting Notes - ${meetingTitle}
**Date:** ${dateLabel}

## Summary
3-5 sentence executive summary of the meeting. What was discussed and why it matters.

## Key Decisions
- Decision 1
- Decision 2
(If no decisions were made, write "No formal decisions recorded.")

## Action Items
- [ ] Action item description — **Owner** (Deadline if mentioned)
- [ ] Next action item — **Owner** (Deadline if mentioned)
(If no action items, write "No action items identified.")

## Discussion Points
Organized by topic. For each topic:
### Topic Name
Brief summary of what was discussed, key arguments, and conclusions.

## Open Questions
- Unresolved questions or items needing follow-up
(If none, write "No open questions.")

## Attendees
List attendees if identifiable from the transcript. If not clear, write "Not identifiable from transcript."

Output only the markdown.`;

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 4096,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, meetingTitle, dateLabel, fileName } }];

const response = $input.first().json;
const markdown = response.content[0].text;

const lines = markdown.split('\n');
let bodyHtml = '';
let inList = false;
let inCheckList = false;
let sectionCount = 0;

function inlineStyles(text) {
  let s = text;
  s = s.replace(/\*\*(.+?)\*\*/g, '<strong style="color:#e2e8f0;">$1</strong>');
  s = s.replace(/\*(.+?)\*/g, '<em>$1</em>');
  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" style="color:#60a5fa; text-decoration:underline;">$1</a>');
  return s;
}

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    if (inCheckList) { bodyHtml += '</table>'; inCheckList = false; }
    continue;
  }
  if (trimmed.startsWith('### ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    if (inCheckList) { bodyHtml += '</table>'; inCheckList = false; }
    bodyHtml += `<h3 style="color:#e2e8f0; font-size:16px; margin:18px 0 6px 0; font-weight:bold; font-family:Arial,sans-serif;">${trimmed.slice(4)}</h3>`;
  } else if (trimmed.startsWith('## ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    if (inCheckList) { bodyHtml += '</table>'; inCheckList = false; }
    sectionCount++;
    const border = sectionCount > 1 ? '<tr><td style="padding:12px 0 0 0; border-top:1px solid #1e3a5f;"></td></tr>' : '';
    bodyHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0">${border}<tr><td style="padding:${sectionCount > 1 ? '16' : '0'}px 0 10px 0;"><h2 style="color:#93c5fd; font-size:20px; margin:0; font-weight:bold; font-family:Arial,sans-serif;">${trimmed.slice(3)}</h2></td></tr></table>`;
  } else if (trimmed.startsWith('# ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    if (inCheckList) { bodyHtml += '</table>'; inCheckList = false; }
  } else if (trimmed.startsWith('- [ ] ') || trimmed.startsWith('- [x] ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    if (!inCheckList) { bodyHtml += '<table width="100%" cellpadding="0" cellspacing="0" border="0">'; inCheckList = true; }
    const checked = trimmed.startsWith('- [x] ');
    const content = inlineStyles(trimmed.slice(6));
    const checkbox = checked ? '&#9745;' : '&#9744;';
    bodyHtml += `<tr><td style="padding:6px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="4" style="background-color:#2563eb;"></td><td style="padding:10px 14px; background-color:#0f1f38; font-family:Arial,sans-serif; font-size:14px; color:#cbd5e1; line-height:1.5;"><span style="font-size:16px;">${checkbox}</span> ${content}</td></tr></table></td></tr>`;
  } else if (trimmed.startsWith('- ')) {
    if (inCheckList) { bodyHtml += '</table>'; inCheckList = false; }
    if (!inList) { bodyHtml += '<table width="100%" cellpadding="0" cellspacing="0" border="0">'; inList = true; }
    const content = inlineStyles(trimmed.slice(2));
    bodyHtml += `<tr><td style="padding:6px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="4" style="background-color:#2563eb;"></td><td style="padding:10px 14px; background-color:#0f1f38; font-family:Arial,sans-serif; font-size:14px; color:#cbd5e1; line-height:1.5;">${content}</td></tr></table></td></tr>`;
  } else {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    if (inCheckList) { bodyHtml += '</table>'; inCheckList = false; }
    bodyHtml += `<p style="color:#cbd5e1; line-height:1.6; margin:8px 0; font-family:Arial,sans-serif; font-size:14px;">${inlineStyles(trimmed)}</p>`;
  }
}
if (inList) bodyHtml += '</table>';
if (inCheckList) bodyHtml += '</table>';

const dateLabel = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const meetingTitle = $('Parse & Build Prompt').first().json.meetingTitle;
const fileDateLabel = $('Parse & Build Prompt').first().json.dateLabel;

const html = `<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd"><html xmlns="http://www.w3.org/1999/xhtml"><head><meta http-equiv="Content-Type" content="text/html; charset=utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Meeting Notes</title></head><body style="margin:0; padding:0; background-color:#0a0f1a; -webkit-text-size-adjust:100%;">
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#0a0f1a;"><tr><td align="center" style="padding:0;">
<table width="660" cellpadding="0" cellspacing="0" border="0" style="max-width:660px; width:100%;">
  <tr><td style="background-color:#0f1b2d; padding:36px 32px 28px 32px; border-bottom:3px solid #2563eb;">
    <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
      <td style="font-family:Arial,sans-serif;">
        <div style="font-size:12px; color:#60a5fa; text-transform:uppercase; letter-spacing:3px; font-weight:bold; margin-bottom:10px;">Meeting Notes</div>
        <h1 style="color:#f1f5f9; font-size:24px; margin:0 0 6px 0; font-weight:bold; font-family:Arial,sans-serif;">${meetingTitle}</h1>
        <div style="color:#94a3b8; font-size:13px; font-family:Arial,sans-serif;">${dateLabel}</div>
      </td>
    </tr></table>
  </td></tr>
  <tr><td style="background-color:#111827; padding:28px 32px;">
    ${bodyHtml}
  </td></tr>
  <tr><td style="background-color:#0a0f1a; padding:20px 32px; border-top:1px solid #1e3a5f; text-align:center; font-family:Arial,sans-serif;">
    <div style="color:#64748b; font-size:12px;">Powered by n8n</div>
  </td></tr>
</table>
</td></tr></table>
</body></html>`;

const outFileName = `${fileDateLabel}-${meetingTitle.replace(/[^a-zA-Z0-9]+/g, '-').toLowerCase()}.md`;

const buffer = Buffer.from(markdown, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, outFileName, 'text/markdown');

return [{ json: { markdown, html, meetingTitle, outFileName }, binary: { data: binaryData } }];
